+pub fn std_dim_tensor_contiguous_f64(
+    input: &[f64],
+    meta: &TensorMeta,
+    dim: usize,
+) -> Result<Vec<f64>, KernelError> {
+    let mut output = var_dim_tensor_contiguous_f64(input, meta, dim)?;
+    for v in &mut output {
+        *v = v.sqrt();
+    }
